---播放泡泡

---@class LBattleSkillActBubble
local LBattleSkillActBubble = classX("LBattleSkillActBubble", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActBubble.Execute(player,effData, playState)
    local _viewMgr = player:GetViewMgr()
    local obj = player:GetTargetAtkUnitView()
    local str =LUtil.GetFaceStr(effData.talkTxt,32)
    local startTime = _viewMgr:GetTime()
    local lastTime = effData.playTime + effData.dissipateTime
    local offset = Vector3.New(effData.effOffsetStart.x,effData.effOffsetStart.y,0)
    obj:ShowBubbleStick(str,lastTime,startTime,effData.effRes,offset)
end

return LBattleSkillActBubble